import React, { useState, useEffect } from 'react';
import { adminUsers, organizations } from '../services/api';
import { useNavigate } from 'react-router-dom';
import './AdminUsers.css';

interface User {
  id: number;
  full_name: string;
  login: string;
  role: 'admin' | 'employee';
  vacation_days_total: number;
  vacation_days_left: number;
  avatar_url?: string;
  department?: string;
  organization_id?: number;
  organization_name?: string;
  created_at: string;
}

interface Organization {
  id: number;
  name: string;
}

const AdminUsers: React.FC = () => {
  const navigate = useNavigate();
  const [users, setUsers] = useState<User[]>([]);
  const [organizationsList, setOrganizationsList] = useState<Organization[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [formData, setFormData] = useState({
    full_name: '',
    login: '',
    password: '',
    role: 'employee' as 'admin' | 'employee',
    vacation_days_total: 28,
    vacation_days_left: 28,
    department: '',
    organization_id: '' as number | string
  });

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [usersResponse, orgsResponse] = await Promise.all([
        adminUsers.getAll(),
        organizations.getAll()
      ]);
      setUsers(usersResponse.data);
      setOrganizationsList(orgsResponse.data);
      setError('');
    } catch (error) {
      console.error('Error fetching data:', error);
      setError('Ошибка загрузки данных');
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const dataToSend = {
        ...formData,
        organization_id: formData.organization_id ? Number(formData.organization_id) : null
      };

      if (editingUser) {
        await adminUsers.update(editingUser.id, dataToSend);
      } else {
        await adminUsers.create(dataToSend);
      }

      setShowModal(false);
      setEditingUser(null);
      setFormData({
        full_name: '',
        login: '',
        password: '',
        role: 'employee',
        vacation_days_total: 28,
        vacation_days_left: 28,
        department: '',
        organization_id: ''
      });
      fetchData();
    } catch (error) {
      console.error('Error saving user:', error);
      setError('Ошибка сохранения');
    }
  };

  const handleEdit = (user: User) => {
    setEditingUser(user);
    setFormData({
      full_name: user.full_name,
      login: user.login,
      password: '',
      role: user.role,
      vacation_days_total: user.vacation_days_total,
      vacation_days_left: user.vacation_days_left,
      department: user.department || '',
      organization_id: user.organization_id || ''
    });
    setShowModal(true);
  };

  const handleDelete = async (id: number) => {
    if (!window.confirm('Удалить пользователя?')) return;
    try {
      await adminUsers.delete(id);
      fetchData();
    } catch (error) {
      console.error('Error deleting user:', error);
      setError('Ошибка удаления');
    }
  };

  const handleResetPassword = async (id: number) => {
    const newPassword = prompt('Введите новый пароль:');
    if (!newPassword) return;

    try {
      await adminUsers.resetPassword(id, newPassword);
      alert('Пароль успешно изменен');
    } catch (error) {
      console.error('Error resetting password:', error);
      setError('Ошибка сброса пароля');
    }
  };

  const filteredUsers = users.filter(user =>
    user.full_name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    user.login.toLowerCase().includes(searchQuery.toLowerCase()) ||
    (user.department && user.department.toLowerCase().includes(searchQuery.toLowerCase()))
  );

  if (loading) {
    return <div className="loading">Загрузка...</div>;
  }

  return (
    <div className="admin-users">
      <div className="users-header">
        <h1>Управление пользователями</h1>
        <button className="add-button" onClick={() => {
          setEditingUser(null);
          setFormData({
            full_name: '',
            login: '',
            password: '',
            role: 'employee',
            vacation_days_total: 28,
            vacation_days_left: 28,
            department: '',
            organization_id: ''
          });
          setShowModal(true);
        }}>
          <i className="fas fa-plus"></i> Добавить пользователя
        </button>
      </div>

      {error && <div className="error-message">{error}</div>}

      <div className="users-search">
        <i className="fas fa-search"></i>
        <input
          type="text"
          placeholder="Поиск по имени, логину или отделу..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
        />
      </div>

      <div className="users-table-container">
        <table className="users-table">
          <thead>
            <tr>
              <th>ID</th>
              <th>Фото</th>
              <th>ФИО</th>
              <th>Логин</th>
              <th>Роль</th>
              <th>Отдел</th>
              <th>Организация</th>
              <th>Отпуск</th>
              <th>Действия</th>
            </tr>
          </thead>
          <tbody>
            {filteredUsers.map(user => (
              <tr key={user.id}>
                <td>{user.id}</td>
                <td>
                  {user.avatar_url ? (
                    <img src={user.avatar_url} alt="avatar" className="user-avatar" />
                  ) : (
                    <div className="user-avatar-placeholder">
                      {user.full_name.charAt(0)}
                    </div>
                  )}
                </td>
                <td>{user.full_name}</td>
                <td>{user.login}</td>
                <td>
                  <span className={`role-badge role-badge--${user.role}`}>
                    {user.role === 'admin' ? 'Админ' : 'Сотрудник'}
                  </span>
                </td>
                <td>{user.department || '-'}</td>
                <td>{user.organization_name || '-'}</td>
                <td>{user.vacation_days_left}/{user.vacation_days_total}</td>
                <td className="actions">
                  <button onClick={() => handleEdit(user)} className="edit-btn" title="Редактировать">
                    <i className="fas fa-edit"></i>
                  </button>
                  <button onClick={() => handleResetPassword(user.id)} className="reset-btn" title="Сбросить пароль">
                    <i className="fas fa-key"></i>
                  </button>
                  <button onClick={() => handleDelete(user.id)} className="delete-btn" title="Удалить">
                    <i className="fas fa-trash"></i>
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Модальное окно для создания/редактирования */}
      {showModal && (
        <div className="modal">
          <div className="modal-content">
            <h2>{editingUser ? 'Редактировать пользователя' : 'Новый пользователь'}</h2>
            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label>ФИО *</label>
                <input
                  type="text"
                  value={formData.full_name}
                  onChange={(e) => setFormData({...formData, full_name: e.target.value})}
                  required
                />
              </div>

              <div className="form-group">
                <label>Логин *</label>
                <input
                  type="text"
                  value={formData.login}
                  onChange={(e) => setFormData({...formData, login: e.target.value})}
                  required
                />
              </div>

              {!editingUser && (
                <div className="form-group">
                  <label>Пароль *</label>
                  <input
                    type="password"
                    value={formData.password}
                    onChange={(e) => setFormData({...formData, password: e.target.value})}
                    required={!editingUser}
                  />
                </div>
              )}

              <div className="form-group">
                <label>Роль</label>
                <select
                  value={formData.role}
                  onChange={(e) => setFormData({...formData, role: e.target.value as 'admin' | 'employee'})}
                >
                  <option value="employee">Сотрудник</option>
                  <option value="admin">Администратор</option>
                </select>
              </div>

              <div className="form-group">
                <label>Отдел</label>
                <input
                  type="text"
                  value={formData.department}
                  onChange={(e) => setFormData({...formData, department: e.target.value})}
                />
              </div>

              <div className="form-group">
                <label>Организация</label>
                <select
                  value={formData.organization_id}
                  onChange={(e) => setFormData({...formData, organization_id: e.target.value})}
                >
                  <option value="">Не выбрана</option>
                  {organizationsList.map(org => (
                    <option key={org.id} value={org.id}>{org.name}</option>
                  ))}
                </select>
              </div>

              <div className="form-row">
                <div className="form-group">
                  <label>Дней отпуска всего</label>
                  <input
                    type="number"
                    value={formData.vacation_days_total}
                    onChange={(e) => setFormData({...formData, vacation_days_total: parseInt(e.target.value) || 0})}
                  />
                </div>

                <div className="form-group">
                  <label>Дней отпуска осталось</label>
                  <input
                    type="number"
                    value={formData.vacation_days_left}
                    onChange={(e) => setFormData({...formData, vacation_days_left: parseInt(e.target.value) || 0})}
                  />
                </div>
              </div>

              <div className="form-actions">
                <button type="submit" className="save-button">
                  {editingUser ? 'Сохранить' : 'Создать'}
                </button>
                <button type="button" className="cancel-button" onClick={() => setShowModal(false)}>
                  Отмена
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminUsers;
